LAYER
	NAME "id_pisos"
	GROUP "MPU"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	HEADER "plantillas/inicio.html"
	TEMPLATE "plantillas/mpu/mpu/id_pisos.html"
	FOOTER "plantillas/fin.html"
	STATUS on
	VALIDATION
    	"id" "^[a-zA-Z0-9 ]+$"
 	END
	DATA "geom FROM (SELECT gid, id_lote, codi_piso, geom FROM geo.tg_pisos) as mpu using unique gid using srid=32718"
	FILTER ("[id_lote]" == "%id%")
	INCLUDE "configuracion/postgresql_mpu.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "codi_piso"
	METADATA
		"wms_group_title" "MPU"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "ID Pisos"
		"wms_abstract" "ID Pisos || Municipalidad Provincial de Urubamba - Cusco :: Perú"
		"wms_credit" "MPU"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "807683.9653000003 8526364.0129 814882.6846000003 8531884.0174"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
        NAME "Piso 1"
        EXPRESSION "01"
        STYLE
            COLOR 140 0 75
            OUTLINECOLOR 0 0 0
            SYMBOL "hatch_diagonal_down"
            SIZE 8
            WIDTH 2
        END
    END
    CLASS
